import{_ as a,o as i,c as l,ag as t}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"创建专属 Key","description":"","frontmatter":{},"headers":[],"relativePath":"guide/create-key.md","filePath":"guide/create-key.md"}'),o={name:"guide/create-key.md"};function r(d,e,s,h,n,c){return i(),l("div",null,[...e[0]||(e[0]=[t(`<h1 id="创建专属-key" tabindex="-1">创建专属 Key <a class="header-anchor" href="#创建专属-key" aria-label="Permalink to &quot;创建专属 Key&quot;">​</a></h1><p>注册登录后，点击创建专属 Key。</p><h2 id="创建步骤" tabindex="-1">创建步骤 <a class="header-anchor" href="#创建步骤" aria-label="Permalink to &quot;创建步骤&quot;">​</a></h2><ol><li>登录 IKunCode 平台</li><li>进入控制台</li><li>点击&quot;创建 Key&quot;按钮</li><li>配置 Key 参数</li><li>保存并复制 Key</li></ol><h2 id="key-类型" tabindex="-1">Key 类型 <a class="header-anchor" href="#key-类型" aria-label="Permalink to &quot;Key 类型&quot;">​</a></h2><p>根据您要使用的工具，选择对应的令牌组：</p><h3 id="claude-code-令牌" tabindex="-1">Claude Code 令牌 <a class="header-anchor" href="#claude-code-令牌" aria-label="Permalink to &quot;Claude Code 令牌&quot;">​</a></h3><p>用于 Claude Code CLI 工具，支持 Claude 系列模型。</p><h3 id="codex-令牌" tabindex="-1">CodeX 令牌 <a class="header-anchor" href="#codex-令牌" aria-label="Permalink to &quot;CodeX 令牌&quot;">​</a></h3><p>用于 CodeX 工具，需要选择&quot;codex测试&quot;令牌组。</p><h3 id="gemini-cli-令牌" tabindex="-1">Gemini CLI 令牌 <a class="header-anchor" href="#gemini-cli-令牌" aria-label="Permalink to &quot;Gemini CLI 令牌&quot;">​</a></h3><p>用于 Gemini CLI 工具，支持 Gemini 系列模型。</p><div class="warning custom-block"><p class="custom-block-title">重要提示</p><p>不同工具需要使用不同的令牌组，请根据您的需求创建对应的 Key。</p></div><h2 id="key-配置参数" tabindex="-1">Key 配置参数 <a class="header-anchor" href="#key-配置参数" aria-label="Permalink to &quot;Key 配置参数&quot;">​</a></h2><p>创建 Key 时，可以配置以下参数：</p><h3 id="名称" tabindex="-1">名称 <a class="header-anchor" href="#名称" aria-label="Permalink to &quot;名称&quot;">​</a></h3><p>为您的 Key 设置一个易于识别的名称，方便管理多个 Key。</p><h3 id="令牌组" tabindex="-1">令牌组 <a class="header-anchor" href="#令牌组" aria-label="Permalink to &quot;令牌组&quot;">​</a></h3><p>选择对应的工具令牌组：</p><ul><li>Claude Code</li><li>CodeX 测试</li><li>Gemini CLI</li></ul><h3 id="配额限制" tabindex="-1">配额限制 <a class="header-anchor" href="#配额限制" aria-label="Permalink to &quot;配额限制&quot;">​</a></h3><p>可以设置：</p><ul><li>无限额度（推荐）</li><li>自定义额度限制</li></ul><h3 id="过期时间" tabindex="-1">过期时间 <a class="header-anchor" href="#过期时间" aria-label="Permalink to &quot;过期时间&quot;">​</a></h3><p>可以设置 Key 的有效期，或选择永不过期。</p><h2 id="安全建议" tabindex="-1">安全建议 <a class="header-anchor" href="#安全建议" aria-label="Permalink to &quot;安全建议&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">安全提醒</p><ul><li>不要将 Key 分享给他人</li><li>不要将 Key 提交到代码仓库</li><li>不要在公开场合展示 Key</li><li>使用环境变量或配置文件存储 Key</li><li>定期更换 Key 提高安全性</li></ul></div><h2 id="保存-key" tabindex="-1">保存 Key <a class="header-anchor" href="#保存-key" aria-label="Permalink to &quot;保存 Key&quot;">​</a></h2><p>创建成功后，请立即保存好您的 Key：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 示例 Key（请替换为您的实际 Key）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sk-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">提示</p><p>Key 只会显示一次，请务必保存好。如果丢失，需要重新创建。</p></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/guide/modify-token">修改令牌设置</a> - 调整令牌参数</li><li><a href="/deploy/claude-code#配置环境变量">配置环境变量</a> - 在工具中使用 Key</li><li><a href="/guide/recharge">充值</a> - 确保账户有足够余额</li></ul>`,33)])])}const x=a(o,[["render",r]]);export{p as __pageData,x as default};
